record_types.code:
type Command (Kind : Command_Kind := Note_Off) is record
   case Kind is
      when Note_Off => null;
      when Note_On =>
         Freq : Frequency;
      when Wait_Ticks =>
         Ticks : Tick_Count;
      when Wait_Note =>
         Note : Note_Duration;
      when Set_Volume =>
         Vol : Volume;
      when Set_Decay =>
         Decay_Ticks : Tick_Count;
      when Set_Sweep =>
         Sweep       : Sweep_Kind;
         Sweep_Len   : Positive;
         Sweep_Ticks : Tick_Count;
      when Set_Width =>
         Width : Pulse_Width;
      when Set_Mode =>
         Mode : Mode_Kind;
   end case;
end record;

